#!/bin/bash

# =============================================================================
# Loko Backend Management Script
# =============================================================================
# Script untuk mengelola project Loko Backend tanpa Docker
# Author: Generated by AI Assistant
# Version: 1.0
# =============================================================================

# Warna untuk output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
PURPLE='\033[0;35m'
CYAN='\033[0;36m'
NC='\033[0m' # No Color

# Konfigurasi
APP_NAME="loko-backend"
BINARY_NAME="app"
LOG_DIR="logs"
TEMP_DIR="temp"
PID_FILE="${APP_NAME}.pid"
LOG_FILE="${LOG_DIR}/${APP_NAME}.log"
ERROR_LOG="${LOG_DIR}/${APP_NAME}_error.log"
ACCESS_LOG="${LOG_DIR}/${APP_NAME}_access.log"

# =============================================================================
# Utility Functions
# =============================================================================

# Fungsi untuk menampilkan banner
show_banner() {
    echo -e "${CYAN}"
    echo "============================================="
    echo "    LOKO BACKEND MANAGEMENT SCRIPT"
    echo "============================================="
    echo -e "${NC}"
}

# Fungsi untuk logging
log() {
    local level=$1
    shift
    local message="$*"
    local timestamp=$(date '+%Y-%m-%d %H:%M:%S')
    
    case $level in
        "INFO")
            echo -e "${GREEN}[INFO]${NC} $message"
            echo "[$timestamp] [INFO] $message" >> "$LOG_FILE"
            ;;
        "WARN")
            echo -e "${YELLOW}[WARN]${NC} $message"
            echo "[$timestamp] [WARN] $message" >> "$LOG_FILE"
            ;;
        "ERROR")
            echo -e "${RED}[ERROR]${NC} $message"
            echo "[$timestamp] [ERROR] $message" >> "$ERROR_LOG"
            ;;
        "DEBUG")
            echo -e "${BLUE}[DEBUG]${NC} $message"
            echo "[$timestamp] [DEBUG] $message" >> "$LOG_FILE"
            ;;
    esac
}

# Fungsi untuk mengecek apakah aplikasi sedang berjalan
is_running() {
    if [ -f "$PID_FILE" ]; then
        local pid=$(cat "$PID_FILE")
        if ps -p "$pid" > /dev/null 2>&1; then
            return 0
        else
            rm -f "$PID_FILE"
            return 1
        fi
    fi
    return 1
}

# Fungsi untuk membuat direktori yang diperlukan
setup_directories() {
    log "INFO" "Membuat direktori yang diperlukan..."
    mkdir -p "$LOG_DIR"
    mkdir -p "$TEMP_DIR"
    mkdir -p "docs"
}

# Fungsi untuk mengecek dependencies
check_dependencies() {
    log "INFO" "Mengecek dependencies..."
    
    # Cek Go
    if ! command -v go &> /dev/null; then
        log "ERROR" "Go tidak terinstall. Silakan install Go terlebih dahulu."
        exit 1
    fi
    
    local go_version=$(go version | awk '{print $3}' | sed 's/go//')
    log "INFO" "Go version: $go_version"
    
    # Cek swag untuk Swagger
    if ! command -v swag &> /dev/null; then
        log "WARN" "Swag tidak terinstall. Install dengan: go install github.com/swaggo/swag/cmd/swag@latest"
    fi
}

# =============================================================================
# Build Functions
# =============================================================================

# Fungsi untuk build aplikasi (native)
build() {
    log "INFO" "Memulai proses build native..."
    
    # Cek syntax error terlebih dahulu
    log "INFO" "Mengecek syntax Go..."
    if ! go vet ./...; then
        log "ERROR" "Ditemukan error dalam kode Go!"
        return 1
    fi
    
    # Build aplikasi
    log "INFO" "Building aplikasi..."
    if go build -o "$BINARY_NAME" .; then
        log "INFO" "Build berhasil! Binary: $BINARY_NAME"
        return 0
    else
        log "ERROR" "Build gagal!"
        return 1
    fi
}

# Fungsi untuk build frontend React dengan Bun
build_frontend() {
    log "INFO" "🚀 Building React Frontend with Bun..."
    
    # Cek apakah direktori frontend ada
    if [ ! -d "frontend" ]; then
        log "ERROR" "Direktori frontend tidak ditemukan!"
        return 1
    fi
    
    # Cek apakah Bun terinstall
    if ! command -v bun &> /dev/null; then
        log "ERROR" "Bun tidak terinstall! Install dengan: curl -fsSL https://bun.sh/install | bash"
        return 1
    fi
    
    # Navigate to frontend directory
    local current_dir=$(pwd)
    cd frontend
    
    # Check if node_modules exists, if not install dependencies
    if [ ! -d "node_modules" ]; then
        log "INFO" "📦 Installing dependencies with Bun..."
        if ! bun install; then
            log "ERROR" "Gagal install dependencies!"
            cd "$current_dir"
            return 1
        fi
    fi
    
    # Build for production
    log "INFO" "🔨 Building for production with Bun..."
    if ! bun run build; then
        log "ERROR" "❌ Frontend build failed!"
        cd "$current_dir"
        return 1
    fi
    
    # Check if build was successful
    if [ -d "dist" ]; then
        log "INFO" "✅ Frontend build completed successfully!"
        log "INFO" "📁 Build output: frontend/dist/"
        log "INFO" "🎉 Frontend ready for Go embed!"
        cd "$current_dir"
        return 0
    else
        log "ERROR" "❌ Frontend build failed - dist directory not found!"
        cd "$current_dir"
        return 1
    fi
}

# Fungsi untuk build backend dengan embedded frontend
build_backend() {
    log "INFO" "🚀 Building Go Backend..."
    
    # Cek apakah build frontend sudah ada
    if [ ! -d "frontend/dist" ]; then
        log "WARN" "Frontend belum di-build. Building frontend terlebih dahulu..."
        if ! build_frontend; then
            log "ERROR" "Gagal build frontend!"
            return 1
        fi
    fi
    
    # Copy frontend dist to server/static for Go embed
    log "INFO" "📁 Copying frontend dist to server/static..."
    rm -rf server/static/assets server/static/index.html server/static/index.html.fiber.gz server/static/dist server/static/vite.svg
    mkdir -p server/static
    cp -a frontend/dist/. server/static/
    if [ ! -d "server/static/assets" ]; then
        log "ERROR" "Gagal menyalin frontend dist ke server/static!"
        return 1
    fi
    
    # Get the binary name from go.mod or use default
    local binary_name=$(grep "module " go.mod | awk '{print $2}' | xargs basename 2>/dev/null)
    if [ -z "$binary_name" ]; then
        binary_name="loko-backend"
    fi
    
    # Create bin directory if it doesn't exist
    mkdir -p bin
    
    # Build for current platform
    log "INFO" "🔨 Building binary: $binary_name"
    if ! go build -o bin/$binary_name .; then
        log "ERROR" "❌ Backend build failed!"
        return 1
    fi
    
    # Check if build was successful
    if [ -f "bin/$binary_name" ]; then
        log "INFO" "✅ Backend build completed successfully!"
        log "INFO" "📁 Binary location: bin/$binary_name"
        log "INFO" "🏃 Run with: ./bin/$binary_name"
        log "INFO" "🎉 Backend ready to run!"
        return 0
    else
        log "ERROR" "❌ Backend build failed - binary not found!"
        return 1
    fi
}

# Fungsi untuk build full stack (frontend + backend)
build_fullstack() {
    log "INFO" "🚀 Building Full Stack Application..."
    
    # Step 1: Build frontend
    log "INFO" "📦 Step 1: Building Frontend..."
    if ! build_frontend; then
        log "ERROR" "❌ Frontend build failed!"
        return 1
    fi
    
    # Step 2: Build backend with embedded frontend
    log "INFO" "🔧 Step 2: Building Backend..."
    if ! build_backend; then
        log "ERROR" "❌ Backend build failed!"
        return 1
    fi
    
    # Get binary name for final message
    local binary_name=$(grep "module " go.mod | awk '{print $2}' | xargs basename 2>/dev/null)
    if [ -z "$binary_name" ]; then
        binary_name="loko-backend"
    fi
    
    log "INFO" "🎉 Full stack build completed successfully!"
    log "INFO" "🏃 Run the application with: ./bin/$binary_name"
    return 0
}

# Fungsi untuk build native (sederhana) - frontend + backend
build_native() {
    log "INFO" "🚀 Building Native Application (Frontend + Backend)..."
    
    # Build frontend dengan Bun
    if ! build_frontend; then
        log "ERROR" "❌ Frontend build failed!"
        return 1
    fi
    
    # Copy frontend dist to backend static
    log "INFO" "📁 Copying frontend dist to backend static..."
    if [ -d "frontend/dist" ]; then
        # Create static directory if it doesn't exist
        mkdir -p server/static
        
        # Remove old dist if exists
        if [ -d "server/static/dist" ]; then
            rm -rf server/static/dist
        fi
        
        # Copy new dist
        cp -r frontend/dist server/static/
        log "INFO" "✅ Frontend dist copied to server/static/dist"
    else
        log "ERROR" "❌ Frontend dist directory not found!"
        return 1
    fi
    
    # Build backend dengan Go embed
    if ! build_backend; then
        log "ERROR" "❌ Backend build failed!"
        return 1
    fi
    
    log "INFO" "🎉 Native build completed successfully!"
    log "INFO" "📁 Binary: bin/${BINARY_NAME}"
    log "INFO" "🚀 Ready to run: ./bin/${BINARY_NAME}"
    return 0
}

# Fungsi untuk build dengan Docker Compose
build_docker() {
    log "INFO" "Memulai proses build dengan Docker Compose..."
    
    # Cek apakah docker-compose.yaml ada
    if [ ! -f "infrastructure/docker/docker-compose.yaml" ]; then
        log "ERROR" "File docker-compose.yaml tidak ditemukan!"
        return 1
    fi
    
    # Cek apakah Docker dan Docker Compose terinstall
    if ! command -v docker &> /dev/null; then
        log "ERROR" "Docker tidak terinstall!"
        return 1
    fi
    
    if ! command -v docker-compose -f infrastructure/docker/docker-compose.yaml &> /dev/null; then
        log "ERROR" "Docker Compose tidak terinstall!"
        return 1
    fi
    
    # Build dengan Docker Compose
    log "INFO" "Building Docker image..."
    if docker-compose -f infrastructure/docker/docker-compose.yaml build; then
        log "INFO" "Docker build berhasil!"
        return 0
    else
        log "ERROR" "Docker build gagal!"
        return 1
    fi
}

# Fungsi untuk rebuild dengan Docker Compose
rebuild() {
    log "INFO" "Memulai proses rebuild dengan Docker Compose..."
    
    # Stop container jika sedang berjalan
    log "INFO" "Menghentikan container yang sedang berjalan..."
    docker-compose -f infrastructure/docker/docker-compose.yaml down 2>/dev/null || true
    
    # Hapus image lama
    log "INFO" "Menghapus image lama..."
    docker-compose -f infrastructure/docker/docker-compose.yaml down --rmi all 2>/dev/null || true
    
    # Build ulang
    log "INFO" "Building ulang Docker image..."
    if docker-compose -f infrastructure/docker/docker-compose.yaml build --no-cache; then
        log "INFO" "Rebuild berhasil!"
        return 0
    else
        log "ERROR" "Rebuild gagal!"
        return 1
    fi
}

# Fungsi untuk build dengan optimasi
build_optimized() {
    log "INFO" "Building dengan optimasi..."
    
    local ldflags="-s -w"
    local build_time=$(date -u '+%Y-%m-%d_%H:%M:%S')
    local git_commit=$(git rev-parse --short HEAD 2>/dev/null || echo "unknown")
    
    ldflags="$ldflags -X main.BuildTime=$build_time -X main.GitCommit=$git_commit"
    
    if go build -ldflags="$ldflags" -o "$BINARY_NAME" .; then
        log "INFO" "Build optimized berhasil!"
        log "INFO" "Build time: $build_time"
        log "INFO" "Git commit: $git_commit"
        return 0
    else
        log "ERROR" "Build optimized gagal!"
        return 1
    fi
}

# Fungsi untuk generate Swagger docs
generate_docs() {
    log "INFO" "Generating Swagger documentation..."
    
    if command -v swag &> /dev/null; then
        if swag init; then
            log "INFO" "Swagger docs berhasil di-generate!"
        else
            log "ERROR" "Gagal generate Swagger docs!"
            return 1
        fi
    else
        log "WARN" "Swag tidak terinstall, skip generate docs"
    fi
}

# =============================================================================
# Run Functions
# =============================================================================

# Fungsi untuk menjalankan aplikasi dalam mode development
run_dev() {
    log "INFO" "Menjalankan aplikasi dalam mode development..."
    
    # Step 1: Cleanup semua build native yang ada
    log "INFO" "🧹 Step 1: Membersihkan semua build native yang ada..."
    
    # Hapus binary lama
    if [ -f "$BINARY_NAME" ]; then
        rm -f "$BINARY_NAME"
        log "INFO" "Binary lama dihapus: $BINARY_NAME"
    fi
    
    # Hapus binary di bin directory
    if [ -d "bin" ]; then
        rm -rf bin/*
        log "INFO" "Direktori bin dibersihkan"
    fi
    
    # Bersihkan frontend dist
    if [ -d "frontend/dist" ]; then
        rm -rf frontend/dist
        log "INFO" "Frontend dist dihapus"
    fi
    
    # Bersihkan server static lama
    log "INFO" "Server static dist dan file lama dihapus"
    rm -rf server/static/assets server/static/index.html server/static/index.html.fiber.gz server/static/dist server/static/vite.svg
    
    # Step 2: Kill proses di port yang mungkin konflik
    log "INFO" "🔧 Step 2: Membersihkan port yang mungkin konflik..."
    kill_ports
    
    # Step 3: Cleanup file temporary dan PID lama
    log "INFO" "🧹 Step 3: Membersihkan file temporary..."
    # Hapus PID file lama jika ada
    if [ -f "$PID_FILE" ]; then
        rm -f "$PID_FILE"
        log "INFO" "PID file lama dihapus"
    fi
    
    # Bersihkan temp directory
    if [ -d "$TEMP_DIR" ]; then
        rm -rf "$TEMP_DIR"/*
        log "INFO" "Direktori temp dibersihkan"
    fi
    
    # Bersihkan log lama untuk development yang fresh
    if [ -f "$LOG_FILE" ]; then
        > "$LOG_FILE"  # Kosongkan file log
        log "INFO" "Log file direset untuk development session baru"
    fi
    
    # Step 4: Build frontend untuk development
    log "INFO" "🔨 Step 4: Building frontend untuk development..."
    if ! build_frontend; then
        log "WARN" "Frontend build gagal, membuat direktori dist kosong untuk development..."
        mkdir -p frontend/dist
        echo '<!DOCTYPE html><html><head><title>Development Mode</title></head><body><h1>Development Mode - Frontend belum ready</h1></body></html>' > frontend/dist/index.html
    fi
    
    # Copy frontend dist ke server static untuk embed
    log "INFO" "📁 Copying frontend dist ke server/static..."
    mkdir -p server/static
    cp -a frontend/dist/. server/static/
    
    # Step 5: Setup environment
    log "INFO" "⚙️  Step 5: Setup environment..."
    if [ -f ".env" ]; then
        log "INFO" "Loading environment dari .env"
        set -a  # automatically export all variables
        source <(cat .env | grep -v '^#' | grep -v '^$' | grep '=')
        set +a  # disable automatic export
    else
        log "WARN" "File .env tidak ditemukan, menggunakan .env.example"
        if [ -f ".env.example" ]; then
            cp .env.example .env
            log "INFO" "File .env dibuat dari .env.example"
        fi
    fi
    
    # Step 6: Setup signal handler untuk Ctrl+C
    log "INFO" "⚙️  Step 6: Setup signal handler..."
    
    # Fungsi untuk cleanup saat Ctrl+C
    cleanup_on_exit() {
        log "INFO" ""
        log "INFO" "🛑 Menerima signal interrupt (Ctrl+C)..."
        log "INFO" "🧹 Membersihkan proses development server..."
        
        if [ -f "$PID_FILE" ]; then
            local pid=$(cat "$PID_FILE")
            if ps -p "$pid" > /dev/null 2>&1; then
                log "INFO" "Menghentikan development server dengan PID: $pid"
                kill -TERM "$pid" 2>/dev/null
                sleep 2
                
                # Cek apakah masih berjalan
                if ps -p "$pid" > /dev/null 2>&1; then
                    log "WARN" "Proses masih berjalan, menggunakan SIGKILL..."
                    kill -KILL "$pid" 2>/dev/null
                fi
            fi
            rm -f "$PID_FILE"
        fi
        
        log "INFO" "✅ Development server berhasil dihentikan"
        log "INFO" "👋 Terima kasih telah menggunakan Loko Backend!"
        exit 0
    }
    
    # Set trap untuk menangkap SIGINT (Ctrl+C) dan SIGTERM
    trap cleanup_on_exit SIGINT SIGTERM
    
    # Step 7: Jalankan development server
    log "INFO" "🚀 Step 7: Starting development server..."
    log "INFO" "Development server akan mendeteksi perubahan file secara otomatis"
    log "INFO" "🛑 Tekan Ctrl+C untuk menghentikan server dengan aman"
    
    go run . 2>&1 | tee "$LOG_FILE" &
    local pid=$!
    echo $pid > "$PID_FILE"
    
    log "INFO" "✅ Development server berjalan dengan PID: $pid"
    log "INFO" "📁 Log file: $LOG_FILE"
    log "INFO" "🔄 Server akan restart otomatis saat ada perubahan kode"
    
    # Wait untuk proses development server
    wait $pid
}

# Fungsi untuk menjalankan aplikasi dari binary
run_prod() {
    log "INFO" "Menjalankan aplikasi dalam mode production..."
    
    # Cek apakah sudah berjalan
    if is_running; then
        log "WARN" "Aplikasi sudah berjalan! PID: $(cat $PID_FILE)"
        return 1
    fi
    
    # Cek apakah binary ada
    if [ ! -f "$BINARY_NAME" ]; then
        log "ERROR" "Binary $BINARY_NAME tidak ditemukan! Jalankan 'build' terlebih dahulu."
        return 1
    fi
    
    # Setup environment
    if [ -f ".env" ]; then
        export $(cat .env | grep -v '^#' | xargs)
    fi
    
    # Jalankan binary
    log "INFO" "Starting production server..."
    nohup "./$BINARY_NAME" > "$LOG_FILE" 2> "$ERROR_LOG" &
    local pid=$!
    echo $pid > "$PID_FILE"
    
    log "INFO" "Aplikasi berjalan dengan PID: $pid"
    log "INFO" "Log file: $LOG_FILE"
    log "INFO" "Error log: $ERROR_LOG"
}

# Fungsi untuk menjalankan dengan hot reload
run_watch() {
    log "INFO" "Menjalankan dengan hot reload..."
    
    # Cek apakah air terinstall
    if ! command -v air &> /dev/null; then
        log "WARN" "Air tidak terinstall. Install dengan: go install github.com/cosmtrek/air@latest"
        log "INFO" "Menggunakan mode development biasa..."
        run_dev
        return
    fi
    
    # Jalankan dengan air
    air
}

# Fungsi untuk menjalankan dengan Docker Compose
run_docker() {
    log "INFO" "Menjalankan aplikasi dengan Docker Compose..."
    
    # Cek apakah docker-compose.yaml ada
    if [ ! -f "infrastructure/docker/docker-compose.yaml" ]; then
        log "ERROR" "File docker-compose.yaml tidak ditemukan!"
        return 1
    fi
    
    # Cek apakah Docker dan Docker Compose terinstall
    if ! command -v docker &> /dev/null; then
        log "ERROR" "Docker tidak terinstall!"
        return 1
    fi
    
    if ! command -v docker-compose -f infrastructure/docker/docker-compose.yaml &> /dev/null; then
        log "ERROR" "Docker Compose tidak terinstall!"
        return 1
    fi
    
    # Jalankan dengan Docker Compose
    log "INFO" "Starting Docker containers..."
    if docker-compose -f infrastructure/docker/docker-compose.yaml up -d; then
        log "INFO" "Docker containers berhasil dijalankan!"
        
        # Tampilkan status container
        log "INFO" "Status containers:"
        docker-compose -f infrastructure/docker/docker-compose.yaml ps
        
        return 0
