        log "ERROR" "Gagal menjalankan Docker containers!"
        return 1
    fi
}

# Fungsi untuk menjalankan Docker Compose dengan build
run_docker_build() {
    log "INFO" "Menjalankan aplikasi dengan Docker Compose (build + run)..."
    
    # Build terlebih dahulu
    if build_docker; then
        log "INFO" "Build berhasil, menjalankan containers..."
        run_docker
    else
        log "ERROR" "Build gagal, tidak dapat menjalankan containers!"
        return 1
    fi
}

# =============================================================================
# Control Functions
# =============================================================================

# Fungsi untuk menghentikan aplikasi (native)
stop() {
    log "INFO" "Menghentikan aplikasi native..."
    
    if is_running; then
        local pid=$(cat "$PID_FILE")
        log "INFO" "Menghentikan proses dengan PID: $pid"
        
        # Kirim SIGTERM terlebih dahulu
        kill -TERM "$pid" 2>/dev/null
        
        # Tunggu beberapa detik
        sleep 3
        
        # Cek apakah masih berjalan
        if ps -p "$pid" > /dev/null 2>&1; then
            log "WARN" "Proses masih berjalan, menggunakan SIGKILL..."
            kill -KILL "$pid" 2>/dev/null
        fi
        
        rm -f "$PID_FILE"
        log "INFO" "Aplikasi berhasil dihentikan"
    else
        log "WARN" "Aplikasi tidak sedang berjalan"
    fi
}

# Fungsi untuk menghentikan Docker containers
stop_docker() {
    log "INFO" "Menghentikan Docker containers..."
    
    # Cek apakah ada container yang berjalan
    if docker-compose -f infrastructure/docker/docker-compose.yaml ps -q | grep -q .; then
        log "INFO" "Menghentikan containers..."
        if docker-compose -f infrastructure/docker/docker-compose.yaml down; then
            log "INFO" "Docker containers berhasil dihentikan"
        else
            log "ERROR" "Gagal menghentikan Docker containers"
            return 1
        fi
    else
        log "WARN" "Tidak ada Docker containers yang berjalan"
    fi
}

# Fungsi untuk kill proses di port tertentu
kill_ports() {
    log "INFO" "Menghentikan proses di port yang digunakan..."
    
    # Port yang umum digunakan oleh aplikasi Loko
    local ports=(1234)
    
    for port in "${ports[@]}"; do
        log "INFO" "Checking port $port..."
        
        # Cari proses yang menggunakan port
        local pids=$(lsof -ti :$port 2>/dev/null)
        
        if [ -n "$pids" ]; then
            log "INFO" "Menghentikan proses di port $port: $pids"
            
            # Kill dengan SIGTERM terlebih dahulu
            echo "$pids" | xargs -r kill -TERM 2>/dev/null
            sleep 2
            
            # Cek apakah masih ada yang berjalan
            local remaining_pids=$(lsof -ti :$port 2>/dev/null)
            if [ -n "$remaining_pids" ]; then
                log "WARN" "Proses masih berjalan di port $port, menggunakan SIGKILL..."
                echo "$remaining_pids" | xargs -r kill -KILL 2>/dev/null
            fi
            
            log "INFO" "Port $port berhasil dibersihkan"
        else
            log "DEBUG" "Port $port tidak digunakan"
        fi
    done
}

# Fungsi untuk cleanup lengkap
cleanup_all() {
    log "INFO" "Melakukan cleanup lengkap..."
    
    # Hapus PID file
    if [ -f "$PID_FILE" ]; then
        rm -f "$PID_FILE"
        log "INFO" "PID file dihapus"
    fi
    
    # Bersihkan temp directory
    if [ -d "$TEMP_DIR" ]; then
        rm -rf "$TEMP_DIR"/*
        log "INFO" "Direktori temp dibersihkan"
    fi
    
    # Hapus binary lama
    if [ -f "$BINARY_NAME" ]; then
        rm -f "$BINARY_NAME"
        log "INFO" "Binary lama dihapus"
    fi
    
    # Hapus binary di bin directory
    if [ -d "bin" ]; then
        rm -rf bin/*
        log "INFO" "Direktori bin dibersihkan"
    fi
    
    # Bersihkan frontend dist
    if [ -d "frontend/dist" ]; then
        rm -rf frontend/dist
        log "INFO" "Frontend dist dihapus"
    fi
    
    # Bersihkan server static
    if [ -d "server/static/dist" ]; then
        rm -rf server/static/dist
        log "INFO" "Server static dist dihapus"
    fi
    
    # Bersihkan node_modules jika ada (untuk fresh install)
    if [ -d "frontend/node_modules" ]; then
        log "INFO" "Menghapus node_modules untuk fresh install..."
        rm -rf frontend/node_modules
    fi
    
    log "INFO" "Cleanup lengkap selesai"
}

# Fungsi untuk rebuild semua komponen
rebuild_all() {
    log "INFO" "🚀 Memulai rebuild semua komponen..."
    
    # Step 1: Install/update frontend dependencies
    log "INFO" "📦 Step 1: Installing frontend dependencies..."
    if [ -d "frontend" ]; then
        cd frontend
        
        # Cek apakah Bun terinstall (required)
        if command -v bun &> /dev/null; then
            log "INFO" "Installing dependencies dengan Bun..."
            if ! bun install; then
                log "ERROR" "❌ Gagal install dependencies dengan Bun!"
                cd ..
                return 1
            fi
        else
            log "ERROR" "❌ Bun tidak terinstall! Install dengan: curl -fsSL https://bun.sh/install | bash"
            cd ..
            return 1
        fi
        
        cd ..
        log "INFO" "✅ Frontend dependencies berhasil diinstall"
    fi
    
    # Step 2: Build frontend
    log "INFO" "🔨 Step 2: Building frontend..."
    if ! build_frontend; then
        log "ERROR" "❌ Frontend build gagal!"
        return 1
    fi
    
    # Step 3: Build backend
    log "INFO" "🔧 Step 3: Building backend..."
    if ! build_backend; then
        log "ERROR" "❌ Backend build gagal!"
        return 1
    fi
    
    # Step 4: Generate docs jika swag tersedia
    log "INFO" "📚 Step 4: Generating documentation..."
    generate_docs
    
    log "INFO" "🎉 Rebuild semua komponen berhasil!"
    log "INFO" "🚀 Aplikasi siap dijalankan dengan: ./manage.sh run-prod"
    
    return 0
}

# =============================================================================
# Simple Deploy/Destroy Functions
# =============================================================================

# Fungsi deploy: Build dan jalankan production dengan Docker
deploy() {
    log "INFO" "🚀 Starting production deployment with Docker..."
    
    # Step 1: Stop existing containers
    log "INFO" "📦 Step 1: Stopping existing containers..."
    docker-compose -f infrastructure/docker/docker-compose.yaml down 2>/dev/null || true
    
    # Step 2: Build Docker images
    log "INFO" "🔨 Step 2: Building Docker images..."
    if ! docker-compose -f infrastructure/docker/docker-compose.yaml build --no-cache; then
        log "ERROR" "❌ Docker build failed!"
        return 1
    fi
    
    # Step 3: Start containers
    log "INFO" "🚀 Step 3: Starting containers..."
    if ! docker-compose -f infrastructure/docker/docker-compose.yaml up -d; then
        log "ERROR" "❌ Failed to start containers!"
        return 1
    fi
    
    # Step 4: Show status
    log "INFO" "📊 Step 4: Deployment status..."
    docker-compose -f infrastructure/docker/docker-compose.yaml ps
    
    log "INFO" "✅ Deployment completed successfully!"
    log "INFO" "📍 Application URL: http://localhost:2000"
    log "INFO" "📍 PostgreSQL: localhost:5432"
    log "INFO" "📋 View logs: ./manage.sh logs-docker"
    log "INFO" "🛑 Destroy: ./manage.sh destroy"
    
    return 0
}

# Fungsi destroy: Stop dan hapus semua containers, networks, dan volumes
destroy() {
    log "WARN" "🗑️  Destroying Docker deployment..."
    log "INFO" "Note: Database volumes will be preserved"
    
    # Confirmation
    read -p "Stop all containers? (yes/no): " confirm
    if [ "$confirm" != "yes" ]; then
        log "INFO" "Destroy cancelled."
        return 0
    fi
    
    # Step 1: Stop containers (keep volumes!)
    log "INFO" "🛑 Step 1: Stopping containers..."
    docker-compose -f infrastructure/docker/docker-compose.yaml down --remove-orphans
    
    # Step 2: Clean up dangling images
    log "INFO" "🧹 Step 2: Cleaning up Docker images..."
    docker image prune -f
    
    log "INFO" "✅ Deployment stopped successfully!"
    log "INFO" "💾 Database volumes preserved"
    log "INFO" "🚀 Deploy again: ./manage.sh deploy"
    
    return 0
}

# Fungsi untuk menghentikan semua (native + docker + ports + rebuild)
stop_all() {
    log "INFO" "🛑 Menghentikan semua aplikasi dan melakukan rebuild..."
    
    # Step 1: Stop native application
    log "INFO" "Step 1: Menghentikan aplikasi native..."
    stop
    
    # Step 2: Stop Docker containers
    log "INFO" "Step 2: Menghentikan Docker containers..."
    stop_docker
    
    # Step 3: Kill processes on ports
    log "INFO" "Step 3: Menghentikan proses di port..."
    kill_ports
    
    # Step 4: Cleanup all files
    log "INFO" "Step 4: Melakukan cleanup..."
    cleanup_all
    
    # Step 5: Rebuild everything
    log "INFO" "Step 5: Rebuild semua komponen..."
    if rebuild_all; then
        log "INFO" "🎉 Stop-all dan rebuild berhasil!"
        log "INFO" "🚀 Aplikasi siap dijalankan dengan: ./manage.sh run-prod"
        return 0
    else
        log "ERROR" "❌ Rebuild gagal!"
        return 1
    fi
}

# Fungsi untuk restart aplikasi (native)
restart() {
    log "INFO" "Restarting aplikasi native dengan build..."
    
    # Step 1: Stop aplikasi yang sedang berjalan
    log "INFO" "🛑 Step 1: Menghentikan aplikasi yang sedang berjalan..."
    stop
    sleep 2
    
    # Step 2: Build frontend
    log "INFO" "🔨 Step 2: Building frontend..."
    if ! build_frontend; then
        log "ERROR" "❌ Frontend build gagal! Restart dibatalkan."
        return 1
    fi
    
    # Step 3: Copy frontend dist ke server/static
    log "INFO" "📁 Step 3: Copying frontend dist ke server/static..."
    if [ -d "frontend/dist" ]; then
        # Create static directory if it doesn't exist
        mkdir -p server/static
        
        # Remove old dist if exists
        if [ -d "server/static/dist" ]; then
            rm -rf server/static/dist
        fi
        
        # Copy new dist
        cp -r frontend/dist server/static/
        log "INFO" "✅ Frontend dist berhasil disalin ke server/static/dist"
    else
        log "ERROR" "❌ Frontend dist directory tidak ditemukan!"
        return 1
    fi
    
    # Step 4: Build backend
    log "INFO" "🔧 Step 4: Building backend..."
    if ! build; then
        log "ERROR" "❌ Backend build gagal! Restart dibatalkan."
        return 1
    fi
    
    # Step 5: Jalankan aplikasi
    log "INFO" "🚀 Step 5: Starting aplikasi..."
    run_prod
    
    if [ $? -eq 0 ]; then
        log "INFO" "🎉 Restart dengan build berhasil!"
        log "INFO" "📊 Gunakan './manage.sh status' untuk cek status aplikasi"
    else
        log "ERROR" "❌ Gagal menjalankan aplikasi setelah build!"
        return 1
    fi
}

# Fungsi untuk restart Docker containers
restart_docker() {
    log "INFO" "Restarting Docker containers..."
    stop_docker
    sleep 2
    run_docker
}

# Fungsi untuk restart semua
restart_all() {
    log "INFO" "Restarting semua aplikasi..."
    stop_all
    sleep 2
    
    # Tanya user mau jalankan yang mana
    echo -e "${YELLOW}Pilih mode untuk restart:${NC}"
    echo "1) Native (go run)"
    echo "2) Docker Compose"
    echo "3) Keduanya"
    read -p "Pilihan (1-3): " choice
    
    case $choice in
        1)
            run_prod
            ;;
        2)
            run_docker
            ;;
        3)
            run_prod &
            run_docker
            ;;
        *)
            log "WARN" "Pilihan tidak valid, menjalankan mode native"
            run_prod
            ;;
    esac
}

# Fungsi untuk mengecek status aplikasi
status() {
    echo -e "${CYAN}=== STATUS APLIKASI NATIVE ===${NC}"
    
    if is_running; then
        local pid=$(cat "$PID_FILE")
        echo -e "${GREEN}Status: RUNNING${NC}"
        echo -e "PID: $pid"
        echo -e "Uptime: $(ps -o etime= -p $pid | tr -d ' ')"
        echo -e "Memory: $(ps -o rss= -p $pid | tr -d ' ') KB"
    else
        echo -e "${RED}Status: STOPPED${NC}"
    fi
    
    echo ""
    echo -e "${CYAN}=== STATUS DOCKER CONTAINERS ===${NC}"
    
    if command -v docker-compose -f infrastructure/docker/docker-compose.yaml &> /dev/null; then
        if [ -f "infrastructure/docker/docker-compose.yaml" ]; then
            # Cek status containers
            local containers=$(docker-compose -f infrastructure/docker/docker-compose.yaml ps -q 2>/dev/null)
            if [ -n "$containers" ]; then
                echo -e "${GREEN}Docker Compose: AVAILABLE${NC}"
                docker-compose -f infrastructure/docker/docker-compose.yaml ps
            else
                echo -e "${YELLOW}Docker Compose: NO RUNNING CONTAINERS${NC}"
            fi
        else
            echo -e "${RED}Docker Compose: docker-compose.yaml NOT FOUND${NC}"
        fi
    else
        echo -e "${RED}Docker Compose: NOT INSTALLED${NC}"
    fi
    
    echo ""
    echo -e "${CYAN}=== INFORMASI SISTEM ===${NC}"
    echo -e "Go version: $(go version | awk '{print $3}')"
    echo -e "OS: $(uname -s)"
    echo -e "Architecture: $(uname -m)"
    
    if [ -f "$BINARY_NAME" ]; then
        echo -e "Binary: ${GREEN}EXISTS${NC} ($(ls -lh $BINARY_NAME | awk '{print $5}'))"
    else
        echo -e "Binary: ${RED}NOT FOUND${NC}"
    fi
    
    # Cek Docker images
    if command -v docker &> /dev/null; then
        echo -e "Docker: ${GREEN}INSTALLED${NC}"
        local images=$(docker images | grep loko-backend | wc -l | tr -d ' ')
        echo -e "Docker Images: $images"
    else
        echo -e "Docker: ${RED}NOT INSTALLED${NC}"
    fi
}

# =============================================================================
# Maintenance Functions
# =============================================================================

# Fungsi untuk membersihkan file temporary
clean() {
    log "INFO" "Membersihkan file temporary..."
    
    # Hentikan aplikasi jika berjalan
    if is_running; then
        log "WARN" "Menghentikan aplikasi terlebih dahulu..."
        stop
    fi
    
    # Hapus binary
    if [ -f "$BINARY_NAME" ]; then
        rm -f "$BINARY_NAME"
        log "INFO" "Binary $BINARY_NAME dihapus"
    fi
    
    # Bersihkan temp directory
    if [ -d "$TEMP_DIR" ]; then
        rm -rf "$TEMP_DIR"/*
        log "INFO" "Direktori temp dibersihkan"
    fi
    
    # Bersihkan log lama (lebih dari 7 hari)
    if [ -d "$LOG_DIR" ]; then
        find "$LOG_DIR" -name "*.log" -mtime +7 -delete 2>/dev/null
        log "INFO" "Log lama (>7 hari) dihapus"
    fi
    
    # Hapus PID file
    rm -f "$PID_FILE"
    
    log "INFO" "Cleanup selesai"
}

# Fungsi untuk install dependencies
install() {
    log "INFO" "Installing dependencies..."
    
    # Go mod tidy
    if go mod tidy; then
        log "INFO" "Go modules berhasil di-update"
    else
        log "ERROR" "Gagal update Go modules"
        return 1
    fi
    
    # Download dependencies
    if go mod download; then
        log "INFO" "Dependencies berhasil di-download"
    else
        log "ERROR" "Gagal download dependencies"
        return 1
    fi
    
    # Install development tools (optional)
    log "INFO" "Installing development tools..."
    
    # Air untuk hot reload
    if ! command -v air &> /dev/null; then
        log "INFO" "Installing air..."
        go install github.com/cosmtrek/air@latest
    fi
    
    # Swag untuk Swagger
    if ! command -v swag &> /dev/null; then
        log "INFO" "Installing swag..."
        go install github.com/swaggo/swag/cmd/swag@latest
    fi
    
    log "INFO" "Installation selesai"
}

# =============================================================================
# Log Functions
# =============================================================================

# Fungsi untuk melihat log
logs() {
    local lines=${1:-50}
    
    echo -e "${CYAN}=== LOGS (Last $lines lines) ===${NC}"
    
    if [ -f "$LOG_FILE" ]; then
        tail -n "$lines" "$LOG_FILE"
    else
        log "WARN" "Log file tidak ditemukan: $LOG_FILE"
    fi
}

# Fungsi untuk melihat error log
error_logs() {
    local lines=${1:-50}
    
    echo -e "${RED}=== ERROR LOGS (Last $lines lines) ===${NC}"
    
    if [ -f "$ERROR_LOG" ]; then
        tail -n "$lines" "$ERROR_LOG"
    else
        log "WARN" "Error log file tidak ditemukan: $ERROR_LOG"
    fi
}

# Fungsi untuk follow log real-time
follow_logs() {
    echo -e "${CYAN}=== FOLLOWING LOGS (Press Ctrl+C to stop) ===${NC}"
    
    if [ -f "$LOG_FILE" ]; then
        tail -f "$LOG_FILE"
    else
        log "WARN" "Log file tidak ditemukan: $LOG_FILE"
    fi
}

# Fungsi untuk melihat Docker logs
logs_docker() {
    local service=${1:-"loko-backend"}
    local lines=${2:-50}
    
    echo -e "${CYAN}=== DOCKER LOGS (Last $lines lines) ===${NC}"
    
    if command -v docker-compose -f infrastructure/docker/docker-compose.yaml &> /dev/null; then
        if docker-compose -f infrastructure/docker/docker-compose.yaml ps -q "$service" > /dev/null 2>&1; then
            docker-compose -f infrastructure/docker/docker-compose.yaml logs --tail="$lines" "$service"
        else
            log "WARN" "Service $service tidak ditemukan atau tidak berjalan"
        fi
    else
        log "ERROR" "Docker Compose tidak terinstall"
    fi
}

# Fungsi untuk follow Docker logs
follow_logs_docker() {
    local service=${1:-"loko-backend"}
    
    echo -e "${CYAN}=== FOLLOWING DOCKER LOGS (Press Ctrl+C to stop) ===${NC}"
    
    if command -v docker-compose -f infrastructure/docker/docker-compose.yaml &> /dev/null; then
        if docker-compose -f infrastructure/docker/docker-compose.yaml ps -q "$service" > /dev/null 2>&1; then
            docker-compose -f infrastructure/docker/docker-compose.yaml logs -f "$service"
        else
            log "WARN" "Service $service tidak ditemukan atau tidak berjalan"
        fi
    else
        log "ERROR" "Docker Compose tidak terinstall"
    fi
}

# =============================================================================
# Testing Functions
# =============================================================================

# Fungsi untuk menjalankan test
test() {
    log "INFO" "Menjalankan tests..."
    
    # Test dengan coverage
    if go test -v -cover ./...; then
        log "INFO" "Semua tests berhasil!"
    else
        log "ERROR" "Ada tests yang gagal!"
        return 1
    fi
}

# Fungsi untuk test dengan coverage detail
test_coverage() {
    log "INFO" "Menjalankan tests dengan coverage detail..."
    
    local coverage_file="coverage.out"
    
    # Jalankan test dengan coverage
    if go test -coverprofile="$coverage_file" ./...; then
        log "INFO" "Tests berhasil!"
        
        # Tampilkan coverage
        go tool cover -func="$coverage_file"
        
        # Generate HTML coverage report
        go tool cover -html="$coverage_file" -o "coverage.html"
        log "INFO" "Coverage report: coverage.html"
    else
        log "ERROR" "Tests gagal!"
        return 1
    fi
}

# =============================================================================
# Database Functions
# =============================================================================

# Fungsi untuk mengecek koneksi database
check_db() {
    log "INFO" "Mengecek koneksi database..."
    
    # Cek apakah aplikasi berjalan
    if ! is_running; then
        log "ERROR" "Aplikasi tidak berjalan. Start aplikasi terlebih dahulu."
        return 1
    fi
    
    # Cek endpoint health (jika ada)
    local health_url="http://localhost:${SERVER_PORT:-8080}/health"
    
    if command -v curl &> /dev/null; then
        if curl -s "$health_url" > /dev/null; then
            log "INFO" "Database connection OK"
        else
            log "ERROR" "Database connection failed"
        fi
    else
        log "WARN" "curl tidak tersedia, tidak bisa cek database"
    fi
}

# Fungsi untuk membersihkan database
clean_db() {
    log "INFO" "Membersihkan database..."

    # Cek apakah psql tersedia - jika tidak, error
    if ! command -v psql &> /dev/null; then
        log "ERROR" "psql tidak ditemukan! Pastikan PostgreSQL client terinstall."
        return 1
    fi

    # Konfirmasi user (double check untuk safety)
    echo -e "${RED}⚠️  PERINGATAN: Command ini akan MENGHAPUS SEMUA DATA di database loko_db!${NC}"
    echo -e "${RED}⚠️  Schema 'public' akan di drop dan dibuat ulang.${NC}"
    read -p "Apakah Anda yakin ingin melanjutkan? (y/N): " confirm

    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        log "INFO" "Operasi dibatalkan oleh user."
        return 0
    fi

    log "WARN" "Menghapus schema public..."
    
    # Execute SQL command
    # Menggunakan PGPASSWORD="" karena user setup bilang password kosong
    if PGPASSWORD="" psql -U macbookairm2 -d loko_db -c "DROP SCHEMA public CASCADE; CREATE SCHEMA public; GRANT ALL ON SCHEMA public TO public;" 2>/tmp/db_clean_err; then
        log "INFO" "✅ Database berhasil dibersihkan (Schema public reset)"
        log "INFO" "Silakan jalankan ulang aplikasi untuk auto-migration."
    else
        log "ERROR" "Gagal membersihkan database!"
        cat /tmp/db_clean_err
        return 1
    fi
}

# =============================================================================
# Environment Functions
# =============================================================================

# Fungsi untuk setup environment
setup_env() {
    log "INFO" "Setting up environment..."
    
    if [ ! -f ".env" ]; then
        if [ -f ".env.example" ]; then
            cp .env.example .env
            log "INFO" "File .env dibuat dari .env.example"
            log "WARN" "Silakan edit .env dan sesuaikan konfigurasi!"
        else
            log "ERROR" "File .env.example tidak ditemukan!"
            return 1
        fi
    else
        log "INFO" "File .env sudah ada"
    fi
    
    # Validasi environment variables yang penting
    validate_env
}

# Fungsi untuk validasi environment
validate_env() {
    log "INFO" "Validating environment variables..."
    
    if [ ! -f ".env" ]; then
        log "ERROR" "File .env tidak ditemukan!"
        return 1
    fi
    
    # Load environment
    source .env
    
    # Cek variabel penting
    local required_vars=("SERVER_PORT" "MONGO_URL" "SECRET_KEY")
    local missing_vars=()
    
    for var in "${required_vars[@]}"; do
        if [ -z "${!var}" ]; then
            missing_vars+=("$var")
        fi
    done
    
    if [ ${#missing_vars[@]} -gt 0 ]; then
        log "ERROR" "Environment variables berikut belum diset:"
        for var in "${missing_vars[@]}"; do
            echo "  - $var"
        done
        return 1
    fi
    
    log "INFO" "Environment validation passed"
}

# Fungsi untuk backup environment
backup_env() {
    log "INFO" "Backing up environment..."
    
    if [ -f ".env" ]; then
        local backup_file=".env.backup.$(date +%Y%m%d_%H%M%S)"
        cp .env "$backup_file"
        log "INFO" "Environment backup: $backup_file"
    else
        log "WARN" "File .env tidak ditemukan, tidak ada yang di-backup"
    fi
}

# =============================================================================
# Monitoring Functions
# =============================================================================

# Fungsi untuk monitoring sistem
monitor() {
    echo -e "${CYAN}=== SYSTEM MONITORING ===${NC}"
    
    # CPU dan Memory usage
    echo -e "${YELLOW}CPU & Memory:${NC}"
    if command -v top &> /dev/null; then
        top -l 1 -n 0 | grep "CPU usage\|PhysMem"
    fi
    
    echo ""
    
    # Disk usage
    echo -e "${YELLOW}Disk Usage:${NC}"
    df -h . | tail -1
    
    echo ""
    
    # Network connections
    echo -e "${YELLOW}Network Connections:${NC}"
    if is_running; then
        local port=${SERVER_PORT:-8080}
        netstat -an | grep ":$port" | head -5
    else
        echo "Aplikasi tidak berjalan"
    fi
    
    echo ""
    
    # Process info
    if is_running; then
        local pid=$(cat "$PID_FILE")
        echo -e "${YELLOW}Process Info:${NC}"
        ps -p "$pid" -o pid,ppid,user,%cpu,%mem,vsz,rss,tty,stat,start,time,command
    fi
}

# Fungsi untuk health check
health_check() {
    log "INFO" "Performing health check..."
    
    local health_status=0
    
    # Cek apakah aplikasi berjalan
    if ! is_running; then
        log "ERROR" "Aplikasi tidak berjalan"
        health_status=1
    else
        log "INFO" "✓ Aplikasi berjalan"
    fi
    
    # Cek koneksi ke port
    local port=${SERVER_PORT:-8080}
    if command -v nc &> /dev/null; then
        if nc -z localhost "$port" 2>/dev/null; then
            log "INFO" "✓ Port $port dapat diakses"
        else
            log "ERROR" "✗ Port $port tidak dapat diakses"
            health_status=1
        fi
    fi
    
    # Cek file log
    if [ -f "$LOG_FILE" ]; then
        local log_size=$(stat -f%z "$LOG_FILE" 2>/dev/null || stat -c%s "$LOG_FILE" 2>/dev/null)
        if [ "$log_size" -gt 0 ]; then
            log "INFO" "✓ Log file aktif ($log_size bytes)"
        else
            log "WARN" "⚠ Log file kosong"
        fi
    else
        log "WARN" "⚠ Log file tidak ditemukan"
    fi
    
    # Cek error dalam log terakhir
    if [ -f "$ERROR_LOG" ]; then
        local recent_errors=$(tail -n 10 "$ERROR_LOG" | grep -c "ERROR" 2>/dev/null || echo 0)
        if [ "$recent_errors" -gt 0 ]; then
            log "WARN" "⚠ Ditemukan $recent_errors error dalam 10 baris terakhir"
        else
            log "INFO" "✓ Tidak ada error terbaru"
        fi
    fi
    
    if [ $health_status -eq 0 ]; then
        log "INFO" "Health check PASSED"
    else
        log "ERROR" "Health check FAILED"
    fi
    
    return $health_status
}

# Fungsi untuk performance metrics
performance() {
    echo -e "${CYAN}=== PERFORMANCE METRICS ===${NC}"
    
    if ! is_running; then
        log "ERROR" "Aplikasi tidak berjalan"
        return 1
    fi
    
    local pid=$(cat "$PID_FILE")
    
    # Memory usage
    echo -e "${YELLOW}Memory Usage:${NC}"
    ps -p "$pid" -o pid,rss,vsz,pmem
    
    # CPU usage
    echo -e "${YELLOW}CPU Usage:${NC}"
    ps -p "$pid" -o pid,pcpu,time
    
    # File descriptors
    echo -e "${YELLOW}File Descriptors:${NC}"
    if [ -d "/proc/$pid/fd" ]; then
        echo "Open FDs: $(ls /proc/$pid/fd | wc -l)"
    fi
    
    # Network connections
    echo -e "${YELLOW}Network Connections:${NC}"
    netstat -an | grep ":${SERVER_PORT:-8080}" | wc -l | xargs echo "Active connections:"
}

# =============================================================================
# Backup Functions
# =============================================================================

# Fungsi untuk backup project
backup() {
    log "INFO" "Creating project backup..."
    
    local backup_dir="backups"
    local timestamp=$(date +%Y%m%d_%H%M%S)
    local backup_name="${APP_NAME}_backup_${timestamp}"
    local backup_path="${backup_dir}/${backup_name}.tar.gz"
    
    # Buat direktori backup
    mkdir -p "$backup_dir"
    
    # Daftar file/direktori yang akan di-backup
    local backup_items=(
        "*.go"
        "go.mod"
        "go.sum"
        ".env.example"
        "server/"
        "docs/"
        "README.md"
        "manage.sh"
    )
    
    # Buat backup
    if tar -czf "$backup_path" "${backup_items[@]}" 2>/dev/null; then
        log "INFO" "Backup berhasil: $backup_path"
        
        # Tampilkan ukuran backup
        local size=$(ls -lh "$backup_path" | awk '{print $5}')
        log "INFO" "Ukuran backup: $size"
    else
        log "ERROR" "Backup gagal!"
        return 1
    fi
}

# Fungsi untuk cleanup backup lama
cleanup_backups() {
    log "INFO" "Cleaning up old backups..."
    
    local backup_dir="backups"
    local keep_days=7
    
    if [ -d "$backup_dir" ]; then
        # Hapus backup lebih dari 7 hari
        find "$backup_dir" -name "*.tar.gz" -mtime +$keep_days -delete 2>/dev/null
        
        # Hitung backup yang tersisa
        local remaining=$(find "$backup_dir" -name "*.tar.gz" | wc -l)
        log "INFO" "Backup tersisa: $remaining file(s)"
    else
        log "INFO" "Direktori backup tidak ditemukan"
    fi
}

# =============================================================================
# Git Functions
# =============================================================================

# Fungsi untuk commit dan push dengan build check
git_push() {
    local message="$1"
    
    if [ -z "$message" ]; then
        log "ERROR" "Commit message diperlukan!"
        echo "Usage: $0 git-push \"commit message\""
        return 1
    fi
    
    log "INFO" "Checking code sebelum commit..."
    
    # Build check
    if ! build; then
        log "ERROR" "Build gagal! Perbaiki error terlebih dahulu."
        return 1
    fi
    
    # Test check
    if ! test; then
        log "ERROR" "Tests gagal! Perbaiki error terlebih dahulu."
        return 1
    fi
    
    log "INFO" "Code check passed, melakukan commit..."
    
    git add .
    git commit -m "$message"
    git pull
    git push
    
    log "INFO" "Git push selesai"
}

