# Fungsi untuk membuat akun administrator
create_admin() {
    log "INFO" "Membuat akun administrator..."
    
    # Cek apakah aplikasi sedang berjalan
    if ! is_running; then
        log "ERROR" "Aplikasi tidak berjalan. Start aplikasi terlebih dahulu dengan: $0 dev atau $0 prod"
        return 1
    fi
    
    # Input data admin
    echo -e "${CYAN}=== SETUP AKUN ADMINISTRATOR ===${NC}"
    echo ""
    
    read -p "Nama lengkap admin: " admin_name
    if [ -z "$admin_name" ]; then
        log "ERROR" "Nama tidak boleh kosong!"
        return 1
    fi
    
    read -p "Username admin: " admin_username
    if [ -z "$admin_username" ]; then
        log "ERROR" "Username tidak boleh kosong!"
        return 1
    fi
    
    read -p "Email admin: " admin_email
    if [ -z "$admin_email" ]; then
        log "ERROR" "Email tidak boleh kosong!"
        return 1
    fi
    
    # Input password dengan konfirmasi
    while true; do
        read -s -p "Password admin: " admin_password
        echo ""
        if [ -z "$admin_password" ]; then
            log "ERROR" "Password tidak boleh kosong!"
            continue
        fi
        
        read -s -p "Konfirmasi password: " admin_password_confirm
        echo ""
        
        if [ "$admin_password" = "$admin_password_confirm" ]; then
            break
        else
            log "ERROR" "Password tidak cocok! Silakan coba lagi."
        fi
    done
    
    # Buat JSON payload
    local json_payload=$(cat <<EOF
{
    "name": "$admin_name",
    "username": "$admin_username",
    "email": "$admin_email",
    "password": "$admin_password",
    "role_id": "Administrator",
    "is_verify": true,
    "is_active": true
}
EOF
)
    
    # Dapatkan port dari environment atau gunakan default
    local server_port=${SERVER_PORT:-8000}
    local api_url="http://localhost:${server_port}/api/user/v1/setup-admin"
    
    log "INFO" "Mengirim request ke: $api_url"
    
    # Kirim request ke API
    if command -v curl &> /dev/null; then
        local response=$(curl -s -w "\n%{http_code}" -X POST \
            -H "Content-Type: application/json" \
            -d "$json_payload" \
            "$api_url")
        
        local http_code=$(echo "$response" | tail -n1)
        local response_body=$(echo "$response" | head -n -1)
        
        if [ "$http_code" = "200" ] || [ "$http_code" = "201" ]; then
            log "INFO" "✅ Akun administrator berhasil dibuat!"
            echo ""
            echo -e "${GREEN}=== DETAIL AKUN ADMINISTRATOR ===${NC}"
            echo -e "${GREEN}Nama:${NC} $admin_name"
            echo -e "${GREEN}Username:${NC} $admin_username"
            echo -e "${GREEN}Email:${NC} $admin_email"
            echo -e "${GREEN}Role:${NC} Administrator"
            echo ""
            echo -e "${YELLOW}⚠️  Simpan informasi login ini dengan aman!${NC}"
            echo ""
        else
            log "ERROR" "Gagal membuat akun administrator!"
            log "ERROR" "HTTP Code: $http_code"
            log "ERROR" "Response: $response_body"
            
            # Coba alternatif: buat langsung ke database
            log "INFO" "Mencoba membuat admin melalui database langsung..."
            create_admin_direct
        fi
    else
        log "ERROR" "curl tidak tersedia. Mencoba membuat admin melalui database langsung..."
        create_admin_direct
    fi
}

# Fungsi alternatif untuk membuat admin langsung ke database
create_admin_direct() {
    log "INFO" "Membuat admin langsung ke database MongoDB..."
    
    # Cek apakah mongosh atau mongo tersedia
    local mongo_cmd=""
    if command -v mongosh &> /dev/null; then
        mongo_cmd="mongosh"
    elif command -v mongo &> /dev/null; then
        mongo_cmd="mongo"
    else
        log "ERROR" "MongoDB client (mongosh/mongo) tidak tersedia!"
        log "INFO" "Silakan install MongoDB client atau gunakan method lain."
        return 1
    fi
    
    # Load environment variables
    if [ -f ".env" ]; then
        source .env
    fi
    
    local mongo_uri=${MONGO_URI:-"mongodb://localhost:27017"}
    local mongo_db=${MONGO_NAME:-"loko"}
    
    # Generate ObjectID dan timestamp
    local object_id=$(date +%s | sha256sum | cut -c1-24)
    local timestamp=$(date -u +"%Y-%m-%dT%H:%M:%S.%3NZ")
    
    # Hash password (simple hash untuk demo - di production gunakan bcrypt)
    local hashed_password=$(echo -n "$admin_password" | sha256sum | cut -d' ' -f1)
    
    # MongoDB script
    local mongo_script="
    use $mongo_db;
    db.users.insertOne({
        _id: ObjectId(),
        name: '$admin_name',
        username: '$admin_username',
        email: '$admin_email',
        password: '$hashed_password',
        role_id: 'Administrator',
        is_verify: true,
        is_active: true,
        credits: 0,
        created_at: new Date(),
        updated_at: new Date()
    });
    "
    
    # Eksekusi MongoDB script
    echo "$mongo_script" | $mongo_cmd "$mongo_uri" --quiet
    
    if [ $? -eq 0 ]; then
        log "INFO" "✅ Akun administrator berhasil dibuat langsung ke database!"
        echo ""
        echo -e "${GREEN}=== DETAIL AKUN ADMINISTRATOR ===${NC}"
        echo -e "${GREEN}Nama:${NC} $admin_name"
        echo -e "${GREEN}Username:${NC} $admin_username"
        echo -e "${GREEN}Email:${NC} $admin_email"
        echo -e "${GREEN}Role:${NC} Administrator"
        echo ""
        echo -e "${YELLOW}⚠️  Password telah di-hash dan disimpan dengan aman.${NC}"
        echo -e "${YELLOW}⚠️  Simpan informasi login ini dengan aman!${NC}"
        echo ""
    else
        log "ERROR" "Gagal membuat akun administrator ke database!"
        return 1
    fi
}

