# =============================================================================
# PostgreSQL Docker Management Functions
# =============================================================================

# Function to get docker-compose -f infrastructure/docker/docker-compose.yaml file based on environment
get_compose_file() {
    local env=${1:-prod}
    if [ "$env" = "dev" ]; then
        echo "docker-compose.dev.yaml"
    else
        echo "infrastructure/docker/docker-compose.yaml"
    fi
}

# Function to get database connection info
get_db_info() {
    local env=${1:-prod}
    if [ "$env" = "dev" ]; then
        echo "postgres-dev loko_dev_user loko_dev_db 5433"
    else
        echo "postgres loko_user loko_db 5432"
    fi
}

# Function to start PostgreSQL services
postgres_up() {
    local env=${1:-prod}
    local compose_file=$(get_compose_file $env)
    
    log "INFO" "Starting Loko Backend PostgreSQL ($env environment)"
    log "INFO" "Using compose file: $compose_file"
    
    docker-compose -f infrastructure/docker/docker-compose.yaml -f $compose_file up -d
    
    log "INFO" "PostgreSQL services started successfully!"
    log "INFO" "Application will be available at: http://localhost:2000"
    
    if [ "$env" = "dev" ]; then
        log "INFO" "pgAdmin will be available at: http://localhost:8080"
        log "INFO" "pgAdmin credentials: admin@loko.dev / admin123"
    fi
}

# Function to stop PostgreSQL services
postgres_down() {
    local env=${1:-prod}
    local compose_file=$(get_compose_file $env)
    
    log "INFO" "Stopping Loko Backend PostgreSQL ($env environment)"
    docker-compose -f infrastructure/docker/docker-compose.yaml -f $compose_file down
    log "INFO" "PostgreSQL services stopped successfully!"
}

# Function to restart PostgreSQL services
postgres_restart() {
    local env=${1:-prod}
    local compose_file=$(get_compose_file $env)
    
    log "INFO" "Restarting Loko Backend PostgreSQL ($env environment)"
    docker-compose -f infrastructure/docker/docker-compose.yaml -f $compose_file restart
    log "INFO" "PostgreSQL services restarted successfully!"
}

# Function to show PostgreSQL logs
postgres_logs() {
    local env=${1:-prod}
    local compose_file=$(get_compose_file $env)
    
    log "INFO" "Showing logs for Loko Backend PostgreSQL ($env environment)"
    docker-compose -f infrastructure/docker/docker-compose.yaml -f $compose_file logs -f
}

# Function to build and start PostgreSQL services
postgres_build() {
    local env=${1:-prod}
    local compose_file=$(get_compose_file $env)
    
    log "INFO" "Building and starting Loko Backend PostgreSQL ($env environment)"
    docker-compose -f infrastructure/docker/docker-compose.yaml -f $compose_file up --build -d
    log "INFO" "PostgreSQL services built and started successfully!"
}

# Function to clean PostgreSQL services
postgres_clean() {
    local env=${1:-prod}
    local compose_file=$(get_compose_file $env)
    
    log "WARN" "Cleaning Loko Backend PostgreSQL ($env environment)"
    log "WARN" "This will remove all containers, networks, and volumes!"
    
    read -p "Are you sure? (y/N): " -n 1 -r
    echo
    if [[ $REPLY =~ ^[Yy]$ ]]; then
        docker-compose -f infrastructure/docker/docker-compose.yaml -f $compose_file down -v --remove-orphans
        log "INFO" "PostgreSQL cleanup completed!"
    else
        log "INFO" "PostgreSQL cleanup cancelled."
    fi
}

# Function to connect to PostgreSQL shell
postgres_shell() {
    local env=${1:-prod}
    local db_info=($(get_db_info $env))
    local container=${db_info[0]}
    local user=${db_info[1]}
    local database=${db_info[2]}
    
    log "INFO" "Connecting to PostgreSQL ($env environment)"
    docker exec -it ${container} psql -U $user -d $database
}

# Function to backup PostgreSQL database
postgres_backup() {
    local env=${1:-prod}
    local db_info=($(get_db_info $env))
    local container=${db_info[0]}
    local user=${db_info[1]}
    local database=${db_info[2]}
    local backup_file="backup_${database}_$(date +%Y%m%d_%H%M%S).sql"
    
    log "INFO" "Backing up PostgreSQL database ($env environment)"
    docker exec $container pg_dump -U $user $database > $backup_file
    log "INFO" "Database backup saved to: $backup_file"
}

# Function to restore PostgreSQL database
postgres_restore() {
    local env=${1:-prod}
    local backup_file=${2}
    
    if [ -z "$backup_file" ]; then
        log "ERROR" "Please specify backup file path"
        echo "Usage: $0 postgres-restore [env] [backup_file]"
        return 1
    fi
    
    if [ ! -f "$backup_file" ]; then
        log "ERROR" "Backup file not found: $backup_file"
        return 1
    fi
    
    local db_info=($(get_db_info $env))
    local container=${db_info[0]}
    local user=${db_info[1]}
    local database=${db_info[2]}
    
    log "WARN" "Restoring PostgreSQL database ($env environment)"
    log "WARN" "This will overwrite the existing database!"
    
    read -p "Are you sure? (y/N): " -n 1 -r
    echo
    if [[ $REPLY =~ ^[Yy]$ ]]; then
        docker exec -i $container psql -U $user $database < $backup_file
        log "INFO" "Database restored successfully!"
    else
        log "INFO" "Restore cancelled."
    fi
}

# Function to show PostgreSQL services status
postgres_status() {
    local env=${1:-prod}
    local compose_file=$(get_compose_file $env)
    
    log "INFO" "PostgreSQL Services Status ($env environment)"
    docker-compose -f infrastructure/docker/docker-compose.yaml -f $compose_file ps
}

# =============================================================================
# PostgreSQL Migration Validation Functions
# =============================================================================

# Function to validate PostgreSQL migration
validate_migration() {
    log "INFO" "🔍 Validating PostgreSQL Migration..."
    
    # 1. Check if required files exist
    log "INFO" "Checking required files..."
    local files=(
        "docker-compose.dev.yaml"
        ".env.dev"
        "init.sql"
        "POSTGRESQL_MIGRATION.md"
    )
    
    for file in "${files[@]}"; do
        if [ -f "$file" ]; then
            log "INFO" "✅ File $file exists"
        else
            log "ERROR" "❌ File $file missing"
            return 1
        fi
    done
    
    # 2. Check Go dependencies
    log "INFO" "Checking Go dependencies..."
    if go mod tidy; then
        log "INFO" "✅ Go dependencies updated"
    else
        log "ERROR" "❌ Go dependencies failed"
        return 1
    fi
    
    if go build .; then
        log "INFO" "✅ Go build successful"
    else
        log "ERROR" "❌ Go build failed"
        return 1
    fi
    
    if go vet ./...; then
        log "INFO" "✅ Go vet passed"
    else
        log "ERROR" "❌ Go vet failed"
        return 1
    fi
    
    # 3. Check Docker Compose syntax
    log "INFO" "Validating Docker Compose files..."
    if docker-compose -f infrastructure/docker/docker-compose.yaml -f docker-compose.yaml config > /dev/null 2>&1; then
        log "INFO" "✅ docker-compose.yaml syntax valid"
    else
        log "ERROR" "❌ docker-compose.yaml syntax invalid"
        return 1
    fi
    
    if docker-compose -f infrastructure/docker/docker-compose.yaml -f docker-compose.dev.yaml config > /dev/null 2>&1; then
        log "INFO" "✅ docker-compose.dev.yaml syntax valid"
    else
        log "ERROR" "❌ docker-compose.dev.yaml syntax invalid"
        return 1
    fi
    
    # 4. Check environment variables
    log "INFO" "Checking environment variables..."
    if [ -f ".env.dev" ]; then
        source .env.dev
        
        local required_vars=(
            "DB_TYPE"
            "DB_HOST"
            "DB_PORT"
            "DB_USER"
            "DB_PASS"
            "DB_NAME"
        )
        
        for var in "${required_vars[@]}"; do
            if [ -n "${!var}" ]; then
                log "INFO" "✅ Environment variable $var is set"
            else
                log "ERROR" "❌ Environment variable $var is missing"
                return 1
            fi
        done
        
        # Check if DB_TYPE is postgres
        if [ "$DB_TYPE" = "postgres" ]; then
            log "INFO" "✅ DB_TYPE is set to postgres"
        else
            log "ERROR" "❌ DB_TYPE should be 'postgres', got '$DB_TYPE'"
            return 1
        fi
    else
        log "ERROR" "❌ .env.dev file not found"
        return 1
    fi
    
    # 5. Check if PostgreSQL driver is available
    log "INFO" "Checking PostgreSQL driver..."
    if grep -q "gorm.io/driver/postgres" go.mod; then
        log "INFO" "✅ PostgreSQL driver found in go.mod"
    else
        log "ERROR" "❌ PostgreSQL driver not found in go.mod"
        return 1
    fi
    
    # 6. Test database connection (if Docker is available)
    log "INFO" "Testing database connection..."
    if command -v docker &> /dev/null; then
        # Check if PostgreSQL container is running
        if docker ps | grep -q postgres; then
            log "INFO" "✅ PostgreSQL container is running"
            
            # Test connection
            if [ -f "cmd/test-db-connection/main.go" ]; then
                if go run cmd/test-db-connection/main.go; then
                    log "INFO" "✅ Database connection test passed"
                else
                    log "WARN" "⚠️ Database connection test failed (container might be starting)"
                fi
            else
                log "WARN" "⚠️ Database connection test script not found"
            fi
        else
            log "WARN" "⚠️ PostgreSQL container not running"
            log "INFO" "To start PostgreSQL: $0 postgres-up dev"
        fi
    else
        log "WARN" "⚠️ Docker not available, skipping container checks"
    fi
    
    echo ""
    log "INFO" "Migration validation completed!"
    log "INFO" "Next steps:"
    echo "  1. Start PostgreSQL: $0 postgres-up dev"
    echo "  2. Test connection: go run cmd/test-db-connection/main.go"
    echo "  3. Start application: $0 dev"
    echo "  4. Check logs: $0 postgres-logs dev"
    echo ""
    log "INFO" "For more information, see POSTGRESQL_MIGRATION.md"
}

# Function to test PostgreSQL connection
test_postgres_connection() {
    log "INFO" "Testing PostgreSQL connection..."
    
    if [ -f "cmd/test-db-connection/main.go" ]; then
        go run cmd/test-db-connection/main.go
    else
        log "ERROR" "Database connection test script not found"
        return 1
    fi
}

